	@Test
	void correlatedExistsUsesTypedSemiEdgeAndPreservesBagMultiplicity() {
		BindingSetAssignment left = assignment(Set.of("shared", "outerOptional"),
				row("shared", iri("match"), "outerOptional", literal("present")),
				row("shared", iri("match"), "outerOptional", literal("present")),
				row("shared", iri("miss")));
		StatementPattern right = existsPattern();
		Filter exists = new Filter(left, new Exists(right));

		Filter selected = assertTypedExists(exists, JoinEdge.Kind.SEMI, JoinEdge.Origin.EXISTS);
		List<BindingSet> actual = evaluate(selected);

		assertEquals(evaluate(exists), actual);
		assertEquals(2, actual.size());
		assertEquals(actual.get(0), actual.get(1), "A SEMI edge must preserve duplicate outer rows");
		assertTrue(actual.stream().allMatch(row -> row.hasBinding("outerOptional")));
		assertTrue(actual.stream().noneMatch(row -> row.hasBinding("rhsOnly")),
				"EXISTS tests the RHS without projecting its bindings into the outer stream");
	}

	@Test
	void correlatedNotExistsUsesTypedAntiEdgeAndPreservesUnboundOuterValues() {
		BindingSetAssignment left = assignment(Set.of("shared", "outerOptional"),
				row("shared", iri("match"), "outerOptional", literal("present")),
				row("shared", iri("match"), "outerOptional", literal("present")),
				row("shared", iri("miss")));
		StatementPattern right = existsPattern();
		Filter notExists = new Filter(left, new Not(new Exists(right)));

		Filter selected = assertTypedExists(notExists, JoinEdge.Kind.ANTI, JoinEdge.Origin.NOT_EXISTS);
		List<BindingSet> actual = evaluate(selected);

		assertEquals(evaluate(notExists), actual);
		assertEquals(1, actual.size());
		assertEquals(iri("miss"), actual.getFirst().getValue("shared"));
		assertFalse(actual.getFirst().hasBinding("outerOptional"),
				"NOT EXISTS must preserve an unbound outer variable on the surviving row");
		assertFalse(actual.getFirst().hasBinding("rhsOnly"));
	}

