	@Test
	void unconditionedLeftJoinUsesTypedLeftEdgeAndPreservesBagMultiplicity() {
		BindingSetAssignment left = assignment(Set.of("shared", "leftValue"),
				row("shared", literal("match"), "leftValue", literal("left-match")),
				row("shared", literal("miss"), "leftValue", literal("left-miss")));
		BindingSetAssignment right = assignment(Set.of("shared", "optional"),
				row("shared", literal("match"), "optional", literal("present")),
				row("shared", literal("match"), "optional", literal("present")));
		LeftJoin optional = new LeftJoin(left, right);

		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());
		Memo memo = new Memo(costModel);
		int rootGroupId = memo.intern(optional.clone());
		MemoExpr rootExpression = memo.group(rootGroupId).expressions().getFirst();
		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId, rootExpression);

		assertTrue(extraction.supported(), extraction.boundaries().toString());
		JoinRegion region = extraction.region();
		JoinEdge leftEdge = assertInstanceOf(JoinEdge.class, region.edges().getFirst());
		assertEquals(JoinEdge.Kind.LEFT, leftEdge.kind());
		assertEquals(2, region.factors().size());
		JoinFactor leftFactor = region.factors()
				.stream()
				.filter(factor -> factor.groupId() == rootExpression.inputs().get(0).groupId())
				.findFirst()
				.orElseThrow();
		JoinFactor rightFactor = region.factors()
				.stream()
				.filter(factor -> factor.groupId() == rootExpression.inputs().get(1).groupId())
				.findFirst()
				.orElseThrow();
		JoinSubset leftSubset = JoinSubset.ofOrdinals(region.factors().indexOf(leftFactor));
		JoinSubset rightSubset = JoinSubset.ofOrdinals(region.factors().indexOf(rightFactor));
		assertTrue(region.isEdgeEligible(leftEdge.id(), leftSubset, rightSubset));
		assertFalse(region.isEdgeEligible(leftEdge.id(), rightSubset, leftSubset),
				"LEFT must never commute its left and right inputs");

		RuleRegistry registry = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();
		CascadesPlan plan = new CascadesPlanner(costModel, registry, CascadesTelemetry.NO_OP)
				.optimize(optional.clone(), OptimizationGoal.root());
		LeftJoin selected = assertInstanceOf(LeftJoin.class, plan.tupleExpr().orElseThrow());
		assertFalse(selected.hasCondition());
		assertInstanceOf(BindingSetAssignment.class, selected.getLeftArg());
		assertInstanceOf(BindingSetAssignment.class, selected.getRightArg());
		assertTrue(plan.memo()
				.group(plan.rootGroupId())
				.expressions()
				.stream()
				.flatMap(expression -> expression.proofs().stream())
				.anyMatch(proof -> proof.facts().contains("typedEdge=LEFT")),
				"The exported LeftJoin must retain its typed LEFT derivation proof");
		List<BindingSet> expected = evaluate(optional);
		List<BindingSet> actual = evaluate(selected);
		assertEquals(expected, actual);
		assertEquals(3, actual.size());
		assertEquals(2, actual.stream().filter(row -> literal("match").equals(row.getValue("shared"))).count());
		BindingSet unmatched = actual.stream()
				.filter(row -> literal("miss").equals(row.getValue("shared")))
				.findFirst()
				.orElseThrow();
		assertFalse(unmatched.hasBinding("optional"), "An unmatched OPTIONAL row must leave RHS bindings unbound");
	}

