	private static void assertUnsupportedAnti(Difference difference,
			MemoJoinRegionExtractor.BoundaryReason expectedReason) {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		int rootGroupId = memo.intern(difference);
		MemoJoinRegionExtractor.Result extraction = MemoJoinRegionExtractor.extract(memo, rootGroupId,
				memo.group(rootGroupId).expressions().getFirst());

		assertFalse(extraction.supported());
		assertEquals(MemoJoinRegionExtractor.Status.NOT_APPLICABLE, extraction.status());
		assertFalse(extraction.completenessBlocking(),
				"A declined optional typed contributor must not make generic optimization incomplete");
		assertTrue(extraction.boundaries().stream().anyMatch(boundary -> boundary.reason() == expectedReason),
				extraction.boundaries().toString());
	}

